    LESSON_PATTERN  = re.compile(r"^BÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã‚Â ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬ÃƒÂ¢Ã¢â‚¬Å¾Ã‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚Â ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¾Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã¢â‚¬Â¦Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â i\s+\d+", re.I)
    ROMAN_HEADER    = re.compile(r"^[IVX]+\.\s+.+")
    NUMBER_HEADER   = re.compile(r"^(\d+(?:\.\d+)*\.)\s+(.+)")

    def parse_number_path(header: str):
        nums = header.split()[0].strip(".")
        return [int(x) for x in nums.split(".")]

    chunks = []
    current_chapter = None
    in_chapter = False
    current_lesson = None
    current_title = None
    section_stack = []
    content_buffer = []

    def flush_buffer():
        if not content_buffer or not section_stack: return
        full_section = " > ".join(h for _, h in section_stack)
        leaf_header = section_stack[-1][1]
        chunks.append(Document(
            page_content="\n".join([leaf_header] + content_buffer).strip(),
            metadata={
                "source": "nhi-khoa-y-hoc-co-truyen",
                "title": current_title,
                "section": full_section
            }
        ))
        content_buffer.clear()

    for line in lines:
        chap_match = CHAPTER_PATTERN.match(line)
        if chap_match:
            flush_buffer()
            current_chapter = chap_match.group(1)
            in_chapter = True
            current_lesson = None; current_title = None; section_stack.clear()
            continue

        if not in_chapter: continue

        if LESSON_PATTERN.match(line):
            flush_buffer()
            section_stack.clear()
            current_lesson = line
            current_title = None
            continue

        if current_lesson and not current_title and line.isupper():
            current_title = line
            continue

        if not current_title: continue

        if ROMAN_HEADER.match(line):
            flush_buffer()
            section_stack = [(1, line)]
            continue

        num_match = NUMBER_HEADER.match(line)
        if num_match:
            if current_chapter == "I": continue
            flush_buffer()
            level = len(parse_number_path(line)) + 1
            while section_stack and section_stack[-1][0] >= level:
                section_stack.pop()
            section_stack.append((level, line))
            continue

        if section_stack:
            content_buffer.append(line)

    flush_buffer()
    return chunks

